            { category: "Marketing & Print", percentage: 0.15 },
            { category: "Speaker Logistics", percentage: 0.1 },
            { category: "Contingency", percentage: 0.05 }
        ],
        wedding: [
            { category: "Venue & Decor", percentage: 0.45 },
